         controller->has_valid_turbidity = false;
         controller->has_valid_level = false;
         controller->clear_streak_count = 0;
         controller->settling_started_ms = 0U;
         controller_set_safe_idle(controller);
     } else {
         /* Both sensors valid - check state machine logic */

         /* Check if level is too low for filtering */
         if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
             /* Stay in COMPLETE with filter off and drain closed */
             controller_set_safe_idle(controller);
         } else if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
             /* Both sensors now valid - can start filtering */
             /* Check if turbidity is high enough to need filtering */
             if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                 controller->filter_on = true;
                 controller->drain_open = false;
                 output.filter_on = true;
                 output.drain_open = false;
                 output.state = CONTROLLER_STATE_FILTERING;
                 output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                 output.changed = true;
             } else {
                 /* Turbidity low enough, stay in SAFE_IDLE */
                 controller_set_safe_idle(controller);
             }
         } else if (controller->state == CONTROLLER_STATE_FILTERING) {
             /* Update clear streak based on turbidity */
             if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                 controller->clear_streak_count++;
             } else {
                 controller->clear_streak_count = 0;
             }

             /* Check if we should transition to SETTLING */
             if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                 controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                 /* Transition to SETTLING after 3 clear streaks */
                 controller->filter_on = false;
                 controller->drain_open = false;
                 controller->clear_streak_count = 0;
                 controller->settling_started_ms = input.now_ms;
                 output.filter_on = false;
                 output.drain_open = false;
                 output.state = CONTROLLER_STATE_SETTLING;
                 output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                 output.changed = true;
