#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Implement the filtering, settling, and draining state machine. */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check sensor timeout - if either sensor is stale for > 1000ms, go safe */
        bool turb_stale = (controller->has_valid_turbidity && 
                          (controller->last_turbidity_ms == 0U || 
                           (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));
        bool level_stale = (controller->has_valid_level && 
                          (controller->last_level_ms == 0U || 
                           (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));

        if (turb_stale || level_stale) {
            /* Stale sensor data - go to safe idle */
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        } else {
            /* Both sensors valid - check state machine logic */

            /* Check if level is too low for filtering */
            if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                /* Stay in COMPLETE with filter off and drain closed */
                controller_set_safe_idle(controller);
            } else if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
                /* Both sensors now valid - can start filtering */
                /* Check if turbidity is high enough to need filtering */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->filter_on = true;
                    controller->drain_open = false;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else {
                    /* Turbidity low enough, stay in SAFE_IDLE */
                    controller_set_safe_idle(controller);
                }
            } else if (controller->state == CONTROLLER_STATE_FILTERING) {
                /* Update clear streak based on turbidity */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }

                /* Check if we should transition to SETTLING */
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Transition to SETTLING after 3 clear streaks */
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    controller->settling_started_ms = input.now_ms;
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = true;
                } else {
                    /* Stay in FILTERING */
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_SETTLING) {
                /* Check settle timer */
                uint32_t elapsed_ms = input.now_ms - controller->settling_started_ms;

                /* Check for disturbance during settling */
                if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                    /* Reset to FILTERING state on disturbance */
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else if (elapsed_ms >= CONTROLLER_SETTLING_MS &&
                           controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                           controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Transition to DRAINING */
                    controller->filter_on = false;
                    controller->drain_open = true;
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = true;
                } else {
                    /* Stay in SETTLING */
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_DRAINING) {
                /* Check for disturbance during draining */
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Close drain, restart filtering */
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else {
                    /* Stay in DRAINING */
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_COMPLETE) {
                /* Level is already low, stay in COMPLETE */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_COMPLETE;
                output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
                output.changed = false;
            }
        }
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check sensor timeout */
        bool turb_stale = (controller->has_valid_turbidity && 
                          (controller->last_turbidity_ms == 0U || 
                           (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));
        bool level_stale = (controller->has_valid_level && 
                          (controller->last_level_ms == 0U || 
                           (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));

        if (turb_stale || level_stale) {
            /* Stale sensor data - go to safe idle */
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
        } else {
            /* Both sensors valid - check state machine logic */

            if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                /* Stay in COMPLETE with filter off and drain closed */
                controller_set_safe_idle(controller);
            } else if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
                /* Both sensors now valid - can start filtering */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->filter_on = true;
                    controller->drain_open = false;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else {
                    /* Turbidity low enough, stay in SAFE_IDLE */
                    controller_set_safe_idle(controller);
                }
            } else if (controller->state == CONTROLLER_STATE_FILTERING) {
                /* Update clear streak based on turbidity */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }

                /* Check if we should transition to SETTLING */
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Transition to SETTLING after 3 clear streaks */
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    controller->settling_started_ms = input.now_ms;
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = true;
                } else {
                    /* Stay in FILTERING */
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_SETTLING) {
                /* Check settle timer */
                uint32_t elapsed_ms = input.now_ms - controller->settling_started_ms;

                /* Check for disturbance during settling */
                if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                    /* Reset to FILTERING state on disturbance */
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else if (elapsed_ms >= CONTROLLER_SETTLING_MS &&
                           controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                           controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Transition to DRAINING */
                    controller->filter_on = false;
                    controller->drain_open = true;
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = true;
                } else {
                    /* Stay in SETTLING */
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_DRAINING) {
                /* Check for disturbance during draining */
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Close drain, restart filtering */
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->clear_streak_count = 0;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                } else {
                    /* Stay in DRAINING */
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = false;
                }
            } else if (controller->state == CONTROLLER_STATE_COMPLETE) {
                /* Level is already low, stay in COMPLETE */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_COMPLETE;
                output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
                output.changed = false;
            }
        }
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}
